module RefModule(CLK, RST, Q);
input CLK, RST;
output reg [3:0] Q;

reg [3:0] unused_bin_counter;

always @(posedge CLK or posedge RST) begin
    if (RST)
        unused_bin_counter <= 4'b0000;
    else
        unused_bin_counter <= unused_bin_counter + 1'b1;
end

always @(unused_bin_counter) begin
    Q = unused_bin_counter ^ (unused_bin_counter >> 1);
end

endmodule
